#[test]
fn put_on_collection_is_error() {
    // Symmetric with get_on_collection_is_error: collection input is
    // an early-rejected error, not a silent no-op.
    let mut conn = RodsConnection::connect_from_env().expect("connect_from_env");
    conn.login_from_auth_file().expect("login_from_auth_file");

    let input = Target::Collection(Collection {
        collection: "/testZone/home/irods".to_string(),
        avus: None,
        access: None,
        timestamps: None,
        contents: None,
        error: None,
    });
    let result = put_one(&mut conn, input, &PutOptions::default());
    assert!(
        result.is_err(),
        "expected error when calling put_one on a collection, got {:?}",
        result
    );
}
